var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はぁ、はぁ、はぁ……！","ENG":"*Huff* *Huff* *Huff...!*","TWN":"哈，哈，哈！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"클리포트 인자를 사용한 참격이 아니었는데도, 이 정도 깊은 상처라니…….","JPN":"クリフォトファクターを用いた斬撃でもなかったのに、これ程の傷とは……","ENG":"That wasn't even a slash using the Qliphoth Factor, and yet, a wound this deep...","TWN":"雖然不是使用神聖因數的斬擊，但竟然造成了如此深的傷口……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"울브즈베인은 신을 죽이는 검…….","JPN":"ウルブズベインは神を殺す剣……","ENG":"The Godslayer, Wolvesbane...","TWN":"狼之災禍是弑神之劍……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 아이러니하게도 마왕 역시 신성한 존재…….","JPN":"そして皮肉なことに魔王もまた神聖な存在……","ENG":"And ironically, a Demon Lord is considered a divine entity...","TWN":"而且諷刺的是，魔王也是神聖的存在……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아마도 사도로서의 힘을 대거 끌어 쓴 이상, 그만큼 그 검에 취약해질 수밖에 없는 거겠죠.","JPN":"使徒としての力を大量に借りた以上、その分あの剣の影響を受けやすくなったのでしょう。","ENG":"By unleashing so much of my power as an Apostle, I must've made myself all the more vulnerable to that blade.","TWN":"或許是因為大量使用了使徒的力量，所以才會對那把劍變得如此脆弱吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇지 않나요, 타기리온……?","JPN":"そうですよね、タギリオン……？","ENG":"Isn't that right, Thagirion...?","TWN":"不是嗎？塔基里翁?"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"후후, 이거 어쩌죠?","JPN":"ふふ、これはこれは。","ENG":"Fu fu, what a shame.","TWN":"呵呵，這可怎麼辦呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"제가 그만 프리마돈나의 무대 뒤편을 봐버리고 말았군요.","JPN":"私としたことが、ついプリマドンナの舞台裏の姿を見てしまいましたね。","ENG":"I ended up peeking behind the prima donna's stage curtain.","TWN":"我不小心看到了歌劇女主角舞台背後的樣子。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 설마 이 정도로 비굴한 모습을 보게 될 줄은 몰랐는데 말이죠.","JPN":"しかしまさか、これ程卑屈な姿を見ることになるとは思いませんでした。","ENG":"Still, I did not expect to see you this pathetic.","TWN":"但沒想到竟然會看到如此卑微的樣子。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"지금 그 모습, 당신의 이름과는 걸맞지 않네요, 스완 클레어.","JPN":"今のあなたは、到底その名を冠するに値する人物には見えませんね、スワン・クレア。","ENG":"This look doesn't suit you at all, Swan Claire.","TWN":"現在的樣子，與你的名字不相稱呢，史旺·克萊爾。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 그야 당연하겠죠.","JPN":"ふふ、当然のことです。","ENG":"Haha. Well, of course not.","TWN":"呵呵，那不是廢話吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 백조가 되길 바랐을 뿐이지, 백조였던 적은 단 한 번도 없습니다.","JPN":"私は白鳥になることに憧れただけで、一度も白鳥であったことはありませんでした。","ENG":"I only ever wanted to be a swan, but never was I to become one.","TWN":"我只是希望成為一隻天鵝，但從來沒有真正成為過天鵝。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"단 한 순간도 살아남기 위한, 발버둥을 멈춘 적이 없으니까요.","JPN":"一瞬たりとも生き残るための足掻きを止めませんでしたから。","ENG":"Not once did I stop struggling to survive, not even for a moment.","TWN":"因為我哪怕一瞬間都從未停止過掙扎求生的努力。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"보세요, 지금 이 순간도 살기 위해, 몸을 낮춰 당신의 하수인을 자처하고 있잖아요?","JPN":"ほら、今この瞬間も生き残るために、身を屈めてあなたの手先を買って出ているでしょう？","ENG":"Look at me now. Even now, I'm groveling to you, calling myself your underling, just to stay alive.","TWN":"看看吧，即使在這一刻，為了活下去，我也願意屈身成為你的僕人，不是嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 이상하네요.","JPN":"しかし、妙ですね。","ENG":"And yet, it's strange.","TWN":"不過有點奇怪啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그렇게 목숨이 아까운 당신이 어째서 계획에도 없는 일을 벌인 거죠?","JPN":"そんなに命が惜しいあなたが、どうして計画にもないことをしたんですか？","ENG":"Why would someone who clings so desperately to life go so far off script?","TWN":"既然你如此珍惜生命，為什麼？做計畫之外的事情呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그것도 당신 스스로의 목숨까지 걸고서 말이죠.","JPN":"それもあなた自身の命まで賭けて。","ENG":"Going as far as to risk her own life?","TWN":"而且還是賭上自己的性命。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 당신이 순순히 계약을 지킨다는 확신이 있다면 이런 짓을 벌일 필요가 없었겠죠.","JPN":"さて、どうでしょう。あなたが素直に契約を守るであろう確信があれば、このようなことをする必要はなかったでしょうね。","ENG":"Well, if I had any faith that you'd honor the deal, I wouldn't have needed to.","TWN":"嗯，如果我確信你會乖乖履行契約，那就沒必要做這種事了吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 계약 조건은 어디까지나, 당신을 현실로 강림하게 만드는 것.","JPN":"私の契約の条件は、あくまであなたを現実に降臨させること。","ENG":"My end of the contract was to bring you into reality.","TWN":"我的契約條件只是讓你降臨到現實中。"},"stage":{"bg":"MS_1201","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이를 위해, 여섯 곳의 대균열에 거울 조각을 심었고, 방주의 봉인을 붕괴시켰습니다.","JPN":"そのために、6つの大亀裂に鏡の破片を植え込み、箱舟の封印を崩壊させました。","ENG":"To do that, I planted mirror shards in all six Grand Dimension Crevices and shattered the Ark's seal.","TWN":"為此，我們在六個大裂縫中植入了鏡子碎片，並破壞了方舟的封印。"},"stage":{"bg":"MS_1201","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"봉인을 무너트렸으니, 머지않아 당신은 현실에 강림할 힘을 얻게 되겠죠.","JPN":"封印を壊したので、間もなくあなたは現実に降臨する力を得られることでしょう。","ENG":"Now that the seal is broken, you'll soon gain the power to manifest in reality.","TWN":"既然已經打破封印，不久之後你就會獲得降臨現實的力量吧。"},"stage":{"bg":"MS_1201","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 저는 당신과의 계약을 충실히 이행했습니다.","JPN":"私はあなたとの契約を忠実に履行しました。","ENG":"In other words, I've fulfilled my part of the bargain.","TWN":"所以我忠實地履行了與你的契約。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 당신이 계약대로 저에게 소원을 넘겨준다는 보장은 어디에도 없죠.","JPN":"しかし､あなたが契約通り、願いを私に譲るという保証はどこにもない。","ENG":"But there's no guarantee you'll grant my wish in return.","TWN":"但是沒有任何保證能確保你會按契約把願望交給我。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서 제 나름대로 고향 세계 런던을 되돌리려 한 겁니다.","JPN":"だから、私なりに故郷の世界のロンドンを元に戻そうとしたまでです。","ENG":"So I made my own attempt to restore London, my home world.","TWN":"所以我才想盡辦法恢復故鄉世界倫敦的樣子。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이제 이해가 되시나요, 암군이여?","JPN":"これでおわかりいただけましたか？　暗君。","ENG":"Do you understand now, Ignorant Monarch?","TWN":"現在明白了嗎？暗君？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그렇군요. 그렇게 생각할 수도 있겠네요.","JPN":"そうですか。そうも考えられますね。","ENG":"I suppose that's one way to see it.","TWN":"是啊，你也可以這麼想。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 그게 제 힘을 멋대로 끌어 쓴 변명은 안 된다고 생각하는데요?","JPN":"でもそれが、私の力を勝手に拝借した言い訳にはならないと思いますが？","ENG":"But don't think that justifies using my power without permission.","TWN":"但是我認為這不能成為你隨意利用我力量的藉口吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"게다가 당신은 고작 당신의 고향 세계 때문에 세계를 만드는 법칙을 건드려 버렸어요.","JPN":"しかもあなたは、故郷の世界程度の理由で世界を作る法則に触れてしまった。","ENG":"Besides, just for your precious home, you tampered with the law of creating a world.","TWN":"而且你僅僅因為自己的故鄉世界，就觸碰了創造世界的法則。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"이로 인해, 다른 마왕이 현실에 개입하게 되었죠.","JPN":"これにより、別の魔王が現実に介入することになりました。","ENG":"Now, thanks to you, other Demon Lords are poking their heads into reality as well.","TWN":"因此，其他魔王開始介入現實。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"이 상황에 대해 당신의 책임이 없다고 생각하는 건 아니겠죠, 스완 클레어?","JPN":"この状況に対し、ご自分の責任がないと思っているわけではありませんね？　スワン・クレア。","ENG":"Surely you don't think you bear no responsibility for that, do you, Swan Claire?","TWN":"關於這種情況，你不會認為自己沒有責任吧，史旺·克萊爾？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"고작 고향 세계라…….","JPN":"故郷の世界程度、か……","ENG":"For my precious home, you say...","TWN":"僅僅為了故鄉世界……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"암군이여, 당신을 따르는 이유 자체가 고작 고향 세계 때문이라는 걸 잊으신 모양이죠?","JPN":"暗君よ、私があなたに従っているそもそもの理由が、故郷の世界程度、のためだということをお忘れのようですね？","ENG":"Ignorant Monarch, you forget that the only reason I followed you in the first place was for my home.","TWN":"暗君啊，看來你已經忘記了我追隨你的理由就是僅僅因為故鄉世界吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러고 보니, 의외로군요.","JPN":"そういえば、意外ですね。","ENG":"Come to think of it, this is unexpected.","TWN":"這麼一想，還真是意外啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 여기 있다는 건, 당신을 마지막으로 막아섰던 모르스를 쓰러트렸다는 뜻일 겁니다.","JPN":"あなたがここにいるということは、最後にあなたの前に立ちはだかったモールスを倒したということ。","ENG":"Your being here must mean that you defeated Mors, the last one standing in your way.","TWN":"你能在這裡，說明你已經擊敗了最後阻擋你的死神。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 곧바로 현실로 강림하지 않고, 구태여 절 찾아오셨다는 건…….","JPN":"しかしすぐ現実に降臨することなく、わざわざ私を訪ねたのは……","ENG":"And yet, instead of descending into reality, you came here to me...","TWN":"但是沒有直接降臨現實，而是特意來找我……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"설마, 이번 일을 추궁하려고 이면세계가 되어버린 제 고향까지 찾아온 건가요?","JPN":"まさか、今回のことを咎めるために、裏世界になった私の故郷までいらっしゃったのですか？","ENG":"Did you really travel all the way to the Counterside, to my fallen home world, just to scold me?","TWN":"難道，這次是為了追究此次事件來到已經成為異界的我的故鄉嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"추궁이라니… 그럴 리가요.","JPN":"咎めるなんて……まさか。","ENG":"Scold you...? Not at all.","TWN":"追究嗎？？不，不對。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"저는 그저 한 가지를 알려드리고 싶은 게 있어서, 이곳을 찾은 겁니다.","JPN":"私はただ、ひとつ伝えたいことがあったからここを訪ねただけです。","ENG":"I only came to deliver a message.","TWN":"我來這裡只是因為有一件事想告訴你。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신은 배우로서 훌륭히 자기 역할을 마쳤답니다. 그건 감사하게 생각하고 있어요.","JPN":"あなたは俳優として、立派にご自身の役割を果たしました。それには感謝しています。","ENG":"You performed your role brilliantly, like a true actress. I do thank you for that.","TWN":"作為演員，你出色地完成了自己的角色。我對此表示感謝。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 저는 성가신 변수는 남겨두지 않는 편이라서요.","JPN":"ですが私は厄介な変数は先に取り除いておく方なので。","ENG":"But I'm not fond of leaving troublesome variables unattended.","TWN":"不過我不喜歡留下麻煩的變數。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"변수? 설마……?","JPN":"変数？　まさか……？","ENG":"Variables? You don't mean–","TWN":"變數？難道?"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그러니 우리 계약은 여기까지랍니다.","JPN":"なので私たちの契約はここまでです。","ENG":"Our contract ends here.","TWN":"所以我們的契約就到此為止吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"커흑…! 심장을……?","JPN":"がはっ……！　心臓を……？","ENG":"Kuh...! My heart...?","TWN":"唔！？臟?"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그러고 보니, 이거 우연이네요.","JPN":"そういえば、偶然にも……","ENG":"Now that I think of it, what a coincidence this is.","TWN":"這麼說來，這還真是巧合呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"이곳은 당신이 따르던 탐정이 목숨을 잃어버린 폭포로군요.","JPN":"ここはあなたが慕っていた探偵が命を落とした滝ですね。","ENG":"This is the same waterfall where that detective you admired lost his life.","TWN":"這裡是你曾追隨的偵探失去生命的瀑布啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"어쩌면 고향 세계를 되돌리는 것보다, 이쪽이 더 빨리 그 남자를 만나는 방법 아닐까요?","JPN":"もしかすると、故郷の世界を元に戻すより、こっちの方があの男に早く出会える方法なのでは？","ENG":"Perhaps this is a faster way to reunite with him than trying to restore your world.","TWN":"或許比起恢復故鄉世界，這邊更快能見到那個男人的方法不是嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"으극……!","JPN":"うぐ……！","ENG":"Krgh...!","TWN":"呃！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"타기… 리온……!","JPN":"タギ……リオン……！","ENG":"Tha... girion...!","TWN":"塔基……萊恩！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신도 처음부터 알고 있었잖아요?","JPN":"あなたも最初からわかっていたでしょう？","ENG":"You knew it from the start, didn't you?","TWN":"你從一開始就知道的吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"이미 끝을 맞이해버린 당신의 세계는 결코 다시 돌아오지 않아요.","JPN":"既に終わりを迎えてしまったあなたの世界は、決して元には戻らない。","ENG":"Your world has already ended. It can never be restored.","TWN":"已經迎來終結的你的世界絕不會再回來了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신이 그 남자와 다시 만나는 건 불가능하다는 걸.","JPN":"あなたとあの男が再会することは、不可能だということを。","ENG":"And there's no way for you to meet that man again.","TWN":"你不可能再見到那個男人了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그러니까 당신도 그 남자가 죽었던 이곳에서 퇴장하도록 하세요.","JPN":"ですからあなたも、あの男が死んだこの場所で退場しなさい。","ENG":"So it's only fitting that you make your exit here. Where he died.","TWN":"所以請你也在這個他死去的地方退場吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그게 제가 당신에게 해드릴 수 있는 유일한 배려니까.","JPN":"それが私があなたにしてあげられる、唯一の配慮です。","ENG":"That's the only mercy I can offer.","TWN":"那是我唯一能給予你的關懷。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그럼, 이만 작별이에요.","JPN":"それでは、さようなら。","ENG":"So, farewell.","TWN":"那麼，現在該說再見了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"스완 클레어.","JPN":"スワン・クレア。","ENG":"Swan Claire.","TWN":"史旺·克萊爾。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BOW"}]`);export{e as default};